"use client";

import { Save } from "lucide-react";
import { useParams, useRouter } from "next/navigation";
import { useEffect, useState } from "react";

import Layout from "@/components/Layout";
import {
  apiJson,
  errorMessage,
} from "@/lib/client/api";
import { notify } from "@/lib/notify";

type StudentForm = {
  id?: number;
  enrollment_number?: string | null;
  admission_number?: string | null;
  first_name?: string | null;
  middle_name?: string | null;
  last_name?: string | null;
  gender?: string | null;
  phone?: string | null;
  email?: string | null;
  father_name?: string | null;
  mother_name?: string | null;
  father_phone?: string | null;
  mother_phone?: string | null;
  roll_number?: string | null;
  current_class_id?: number | null;
  current_section_id?: number | null;
};

export default function EditStudentPage() {
  const params = useParams();
  const router = useRouter();
  const [form, setForm] =
    useState<StudentForm>({});
  const [classes, setClasses] =
    useState<any[]>([]);
  const [sections, setSections] =
    useState<any[]>([]);
  const [saving, setSaving] =
    useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [
        studentPayload,
        classRows,
        sectionRows,
      ] = await Promise.all([
        apiJson<any>(
          `/api/students/${params.id}`
        ),
        apiJson<any[]>("/api/classes"),
        apiJson<any[]>("/api/sections"),
      ]);

      setForm(
        studentPayload.student ??
          studentPayload
      );
      setClasses(
        Array.isArray(classRows)
          ? classRows
          : []
      );
      setSections(
        Array.isArray(sectionRows)
          ? sectionRows
          : []
      );
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to load student"
        )
      );
    }
  };

  const updateField = (
    key: keyof StudentForm,
    value: string
  ) => {
    setForm((previous) => ({
      ...previous,
      [key]:
        key.includes("_id") &&
        value
          ? Number(value)
          : value,
    }));
  };

  const updateStudent = async () => {
    try {
      setSaving(true);
      await apiJson(
        `/api/students/${params.id}`,
        {
          method: "PUT",
          headers: {
            "Content-Type":
              "application/json",
          },
          body: JSON.stringify(form),
        }
      );

      notify.success(
        "Student updated"
      );
      router.push("/students/list");
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to update student"
        )
      );
    } finally {
      setSaving(false);
    }
  };

  const filteredSections =
    sections.filter(
      (section) =>
        !form.current_class_id ||
        Number(section.class_id) ===
          Number(form.current_class_id)
    );

  return (
    <Layout>
      <div className="mx-auto max-w-6xl space-y-6">
        <div>
          <h1 className="text-3xl font-black md:text-4xl">
            Edit Student
          </h1>
          <p className="mt-1 text-sm text-slate-600">
            Update the student profile for the selected school and academic year.
          </p>
        </div>

        <div className="tt-card tt-card-pad">
          <div
            className="
              grid
              gap-4
              md:grid-cols-2
              xl:grid-cols-3
            "
          >
            <Field
              label="Enrollment Number"
              value={
                form.enrollment_number ||
                ""
              }
              onChange={(value) =>
                updateField(
                  "enrollment_number",
                  value
                )
              }
            />
            <Field
              label="Admission Number"
              value={
                form.admission_number ||
                ""
              }
              onChange={(value) =>
                updateField(
                  "admission_number",
                  value
                )
              }
            />
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Gender
              </span>
              <select
                className="input"
                value={form.gender || ""}
                onChange={(event) =>
                  updateField(
                    "gender",
                    event.target.value
                  )
                }
              >
                <option value="">
                  Select Gender
                </option>
                <option value="Male">
                  Male
                </option>
                <option value="Female">
                  Female
                </option>
              </select>
            </label>
            <Field
              label="First Name"
              value={form.first_name || ""}
              onChange={(value) =>
                updateField(
                  "first_name",
                  value
                )
              }
            />
            <Field
              label="Middle Name"
              value={
                form.middle_name || ""
              }
              onChange={(value) =>
                updateField(
                  "middle_name",
                  value
                )
              }
            />
            <Field
              label="Last Name"
              value={form.last_name || ""}
              onChange={(value) =>
                updateField(
                  "last_name",
                  value
                )
              }
            />
            <Field
              label="Phone"
              value={form.phone || ""}
              onChange={(value) =>
                updateField(
                  "phone",
                  value
                )
              }
            />
            <Field
              label="Email"
              value={form.email || ""}
              onChange={(value) =>
                updateField(
                  "email",
                  value
                )
              }
            />
            <Field
              label="Father Name"
              value={
                form.father_name || ""
              }
              onChange={(value) =>
                updateField(
                  "father_name",
                  value
                )
              }
            />
            <Field
              label="Mother Name"
              value={
                form.mother_name || ""
              }
              onChange={(value) =>
                updateField(
                  "mother_name",
                  value
                )
              }
            />
            <Field
              label="Father Phone"
              value={
                form.father_phone || ""
              }
              onChange={(value) =>
                updateField(
                  "father_phone",
                  value
                )
              }
            />
            <Field
              label="Mother Phone"
              value={
                form.mother_phone || ""
              }
              onChange={(value) =>
                updateField(
                  "mother_phone",
                  value
                )
              }
            />
            <Field
              label="Roll Number"
              value={
                form.roll_number || ""
              }
              onChange={(value) =>
                updateField(
                  "roll_number",
                  value
                )
              }
            />
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Class
              </span>
              <select
                className="input"
                value={
                  form.current_class_id ||
                  ""
                }
                onChange={(event) =>
                  setForm(
                    (previous) => ({
                      ...previous,
                      current_class_id:
                        event.target.value
                          ? Number(
                              event.target
                                .value
                            )
                          : null,
                      current_section_id:
                        null,
                    })
                  )
                }
              >
                <option value="">
                  Select Class
                </option>
                {classes.map((item) => (
                  <option
                    key={item.id}
                    value={item.id}
                  >
                    {item.class_name}
                  </option>
                ))}
              </select>
            </label>
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Section
              </span>
              <select
                className="input"
                value={
                  form.current_section_id ||
                  ""
                }
                onChange={(event) =>
                  updateField(
                    "current_section_id",
                    event.target.value
                  )
                }
              >
                <option value="">
                  Select Section
                </option>
                {filteredSections.map(
                  (item) => (
                    <option
                      key={item.id}
                      value={item.id}
                    >
                      {item.section_name}
                    </option>
                  )
                )}
              </select>
            </label>
          </div>

          <button
            onClick={updateStudent}
            disabled={saving}
            className="tt-button mt-6 inline-flex items-center gap-2"
          >
            <Save size={17} />
            {saving
              ? "Updating..."
              : "Update Student"}
          </button>
        </div>
      </div>
    </Layout>
  );
}

function Field({
  label,
  value,
  onChange,
}: {
  label: string;
  value: string;
  onChange: (value: string) => void;
}) {
  return (
    <label className="min-w-0">
      <span className="mb-1 block text-sm font-bold text-slate-700">
        {label}
      </span>
      <input
        className="input"
        value={value}
        onChange={(event) =>
          onChange(event.target.value)
        }
      />
    </label>
  );
}
